# Decorator to add custom sanitized context
def track_performance(operation_name):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Add safe custom context (no sensitive data)
            elasticapm.set_custom_context({
                'operation': operation_name,
                'user_id': g.get('user_id', 'anonymous')  # Only non-sensitive IDs
            })
            
            # Add safe labels
            elasticapm.label(operation=operation_name)
            
            return f(*args, **kwargs)
        return decorated_function
    return decorator


